/**
 * Generate Diffbot firewall config.
 *
 * Data source: https://docs.diffbot.com
 *
 * Diffbot authenticates with an API token passed as the `token` query
 * parameter on every request.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.diffbot.com";
// Format: 32 hex chars
const PLACEHOLDER_VALUE = "c0ffeesafelocal5afe10ca1c0ffeesa";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Diffbot API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:diffbot",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const diffbotFirewall = {",
    '  name: "diffbot",',
    '  description: "Diffbot API",',
    "  placeholders: {",
    `    DIFFBOT_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.diffbot.com",',
    "      auth: {",
    "        query: {",
    '          token: "${{ secrets.DIFFBOT_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Diffbot firewall config...");
  const ts = generateTypeScript();
  writeOutput("diffbot", ts, import.meta.dirname);
}
